import pool from './deeptrader-backend/config/database.js';

try {
  const res = await pool.query(
    `select column_name, data_type
     from information_schema.columns
     where table_schema='public' and table_name='portfolios'
     order by ordinal_position`
  );
  console.log('PORTFOLIOS_COLUMNS', JSON.stringify(res.rows));
  await pool.end();
} catch (e) {
  console.error('PORTFOLIOS_COLUMNS_ERROR', e && e.message ? e.message : String(e));
  try { await pool.end(); } catch {}
  process.exit(1);
}
